import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getRealEstatePortfolio(walletAddress) {
  const resp = await client.BalanceService.getTokenBalancesForWalletAddress(
    "eth-mainnet", walletAddress, { nft: true }
  );
  const rwaTokens = (resp.data?.items ?? []).filter(
    item => item.contract_name?.toLowerCase().includes("real") ||
            item.contract_name?.toLowerCase().includes("estate")
  );
  return rwaTokens;
}
